// Prevents a function from being called too frequently, delaying its execution until after a certain amount of time has passed since the last call.
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Example usage:
function expensiveOperation(input) {
  console.log(`Processing input: ${input}`);
  // Simulate a computationally expensive task
  for (let i = 0; i < 1000000; i++) {
    Math.sqrt(i);
  }
  console.log(`Finished processing input: ${input}`);
}

const debouncedOperation = debounce(expensiveOperation, 300);

// Simulate rapid input changes
debouncedOperation("A");
debouncedOperation("B");
debouncedOperation("C");
debouncedOperation("D");

// Only the last call (with input "D") will trigger the expensiveOperation after 300ms of inactivity.
